output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?appointer WHERE {
  wd:Q2579905 wdt:P748 ?appointer .
}

args.sparql:
SELECT ?appointer (SAMPLE(?label) AS ?label) WHERE {
  wd:Q2579905 wdt:P748 ?appointer.
  ?appointer rdfs:label ?label.
  FILTER(LANG(?label) = "en")
}
GROUP BY ?appointer

SELECT ?appointer (SAMPLE(?appointerLabel) AS ?label) WHERE {
  wd:Q2579905 wdt:P748 ?appointer.
  ?appointer rdfs:label ?appointerLabel.
  FILTER(LANG(?appointerLabel) = "en")
}
GROUP BY ?appointer
